        if (lastName == null || lastName.trim().isEmpty()) {
            session.setAttribute("profileMessage", "Họ không được để trống");
            session.setAttribute("profileMessageType", "error");
            response.sendRedirect(request.getContextPath() + "/user/profile");
            return;
        }

        if (phone == null || phone.trim().isEmpty() || !phone.matches("^[0-9]{10,20}$")) {
            session.setAttribute("profileMessage", "Số điện thoại không hợp lệ (10-20 chữ số)");
            session.setAttribute("profileMessageType", "error");
            response.sendRedirect(request.getContextPath() + "/user/profile");
            return;
        }

        // Update user fields
        currentUser.setFirstName(firstName.trim());
        currentUser.setLastName(lastName.trim());
        currentUser.setPhone(phone.trim());

        // Update gender if provided
        if (gender != null && !gender.trim().isEmpty()) {
            try {
                Gender genderValue = mapGender(gender);
                if (genderValue != null) {
                    currentUser.setGender(genderValue);
                }
            } catch (IllegalArgumentException e) {
                // Keep existing gender if invalid value provided
            }
        }

        // Update date of birth if provided
        if (dob != null && !dob.trim().isEmpty()) {
            try {
                currentUser.setDateOfBirth(LocalDate.parse(dob, DateTimeFormatter.ISO_LOCAL_DATE));
            } catch (Exception e) {
                // Keep existing date of birth if invalid
            }
        }

        // Save to database
        ProfileService profileService = new ProfileService();
        profileService.updateProfile(currentUser);

        // Update session with all attribute names (consistent with LoginServlet)
        session.setAttribute("currentUser", currentUser);
        session.setAttribute("userInSession", currentUser);
        session.setAttribute("user", currentUser);
        session.setAttribute("authUser", currentUser);

        session.setAttribute("profileMessage", "Cập nhật hồ sơ thành công!");
        session.setAttribute("profileMessageType", "success");
        response.sendRedirect(request.getContextPath() + "/user/profile");
    }

}
    private Gender mapGender(String vietnameseGender) {
        if (vietnameseGender == null || vietnameseGender.trim().isEmpty()) {
            return null;
        }

        switch (vietnameseGender.trim()) {
            case "Nam":
                return Gender.MALE;
            case "Nữ":
                return Gender.FEMALE;
            case "Khác":
                return Gender.OTHER;
            default:
                return null;
        }
    }

    private void changeUserAvatar(HttpServletRequest request, HttpServletResponse response,
                                  User currentUser, HttpSession session) throws IOException, ServletException {
        // Check if Cloudinary is configured
        if (!CloudinaryUtil.isConfigured()) {
            session.setAttribute("profileMessage", "Hệ thống chưa được cấu hình để tải hình ảnh");
            session.setAttribute("profileMessageType", "error");
            response.sendRedirect(request.getContextPath() + "/user/profile");
            return;
        }

        // Get the uploaded file
        Part filePart = request.getPart("avatarFile");
        if (filePart == null || filePart.getSize() == 0) {
            session.setAttribute("profileMessage", "Vui lòng chọn một tệp hình ảnh");
            session.setAttribute("profileMessageType", "error");
            response.sendRedirect(request.getContextPath() + "/user/profile");
            return;
        }

        // Validate file type
        String contentType = filePart.getContentType();
        if (contentType == null || !contentType.startsWith("image/")) {
            session.setAttribute("profileMessage", "Tệp phải là một hình ảnh");
            session.setAttribute("profileMessageType", "error");
            response.sendRedirect(request.getContextPath() + "/user/profile");
            return;
        }

        // Validate file size (max 5MB)
        if (filePart.getSize() > 5 * 1024 * 1024) {
            session.setAttribute("profileMessage", "Hình ảnh không được vượt quá 5MB");
            session.setAttribute("profileMessageType", "error");
            response.sendRedirect(request.getContextPath() + "/user/profile");
            return;
        }

        try {
            // Delete old avatar from Cloudinary if exists
            if (currentUser.getAvatarPublicId() != null && !currentUser.getAvatarPublicId().isEmpty()) {
                CloudinaryUtil.deleteImage(currentUser.getAvatarPublicId());
            }

            // Generate unique public ID for the avatar
            String publicId = "avatar_user_" + currentUser.getId() + "_" + System.currentTimeMillis();

            // Upload image to Cloudinary
            Map<String, Object> uploadResult = CloudinaryUtil.uploadImage(
                filePart.getInputStream(),
                filePart.getSubmittedFileName(),
                "avatars",
                publicId
            );

            // Update user avatar information
            currentUser.setAvatarUrl((String) uploadResult.get("secure_url"));
            currentUser.setAvatarPublicId((String) uploadResult.get("public_id"));

            // Save to database
            ProfileService profileService = new ProfileService();
            profileService.updateProfile(currentUser);

            // Update session
            session.setAttribute("currentUser", currentUser);
            session.setAttribute("userInSession", currentUser);
            session.setAttribute("user", currentUser);
            session.setAttribute("authUser", currentUser);

            session.setAttribute("profileMessage", "Cập nhật ảnh đại diện thành công!");
            session.setAttribute("profileMessageType", "success");

            Logger.getLogger(ProfileServlet.class.getName()).info("Avatar updated successfully for user: " + currentUser.getId());
        } catch (IOException e) {
            Logger.getLogger(ProfileServlet.class.getName()).log(Level.SEVERE, "Error uploading avatar", e);
            session.setAttribute("profileMessage", "Lỗi tải lên hình ảnh: " + e.getMessage());
            session.setAttribute("profileMessageType", "error");
        }

        response.sendRedirect(request.getContextPath() + "/user/profile");
    }

package nlu.fit.web.souvenirecommerce.auth.servlet;

import com.google.gson.JsonObject;
import jakarta.servlet.ServletException;
import jakarta.servlet.annotation.WebServlet;
import jakarta.servlet.http.HttpServlet;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import jakarta.servlet.http.HttpSession;
import nlu.fit.web.souvenirecommerce.dao.IUserDAO;
import nlu.fit.web.souvenirecommerce.auth.dao.AuthDAO;
import nlu.fit.web.souvenirecommerce.enums.Gender;
import nlu.fit.web.souvenirecommerce.util.EmailUtil;

import java.io.IOException;
import java.io.PrintWriter;

@WebServlet(urlPatterns = {"/api/signup", "/signup"})
public class SignupServlet extends HttpServlet {
    private IUserDAO userDAO;

    @Override
    public void init() throws ServletException {
        userDAO = new AuthDAO();
    }

    @Override
    protected void doGet(HttpServletRequest req, HttpServletResponse resp) throws ServletException, IOException {
        req.getRequestDispatcher("/WEB-INF/views/auth/signup.jsp").forward(req, resp);
    }

    protected void doPost(HttpServletRequest req, HttpServletResponse resp) throws ServletException, IOException {
        resp.setContentType("application/json;charset=UTF-8");
        req.setCharacterEncoding("UTF-8");

        JsonObject jsonResponse = new JsonObject();
        String email = EmailUtil.normalizeEmail(req.getParameter("email"));
        String firstName = normalize(req.getParameter("firstName"));
        String lastName = normalize(req.getParameter("lastName"));
        String phone = normalize(req.getParameter("phone"));
        String gender = normalize(req.getParameter("gender"));
        String password = req.getParameter("password");
        String confirmPassword = req.getParameter("confirmPassword");

        String validationError = validate(email, firstName, lastName, phone, gender, password, confirmPassword);
        if (validationError != null) {
            writeJson(resp, jsonResponse, "error", validationError);
            return;
        }

        HttpSession session = req.getSession(false);
        String verifiedEmail = session == null ? null : (String) session.getAttribute("signupVerifiedEmail");
        if (!email.equals(verifiedEmail)) {
            writeJson(resp, jsonResponse, "error", "Vui lòng xác thực email trước khi đăng ký");
            return;
        }

        if (userDAO.hasEmailExist(email)) {
            writeJson(resp, jsonResponse, "error", "Email này đã được đăng ký");
            return;
        }

        try {
            boolean registered = userDAO.createUser(email, password, firstName, lastName, phone, gender).isPresent();
            if (!registered) {
                writeJson(resp, jsonResponse, "error", "Không thể tạo tài khoản. Vui lòng thử lại");
                return;
            }
        } catch (RuntimeException e) {
            e.printStackTrace();
            writeJson(resp, jsonResponse, "error", "Không thể tạo tài khoản. Vui lòng thử lại");
            return;
        }

        session.removeAttribute("signupEmail");
        session.removeAttribute("signupVerifiedEmail");

        writeJson(resp, jsonResponse, "success", "Tạo tài khoản thành công");

        // Create UserSession and setAttributes
    }

    private String validate(String email, String firstName, String lastName, String phone, String gender,
                            String password, String confirmPassword) {
        if (email == null || email.isEmpty()) {
            return "Email không được để trống";
        }

        if (!email.matches("^[A-Za-z0-9+_.-]+@(.+)$")) {
            return "Email không hợp lệ";
        }

        if (lastName == null || lastName.isBlank()) {
            return "Họ không được để trống";
        }

        if (firstName == null || firstName.isBlank()) {
            return "Tên không được để trống";
        }

        if (phone == null || !phone.matches("^[0-9]{10,20}$")) {
            return "Số điện thoại phải từ 10-20 chữ số";
        }

        if (gender == null || gender.isBlank()) {
            return "Vui lòng chọn giới tính";
        }

        try {
            Gender.valueOf(gender.toUpperCase());
        } catch (IllegalArgumentException e) {
            return "Giới tính không hợp lệ";
        }

        if (password == null || password.length() < 8) {
            return "Mật khẩu phải ít nhất 8 ký tự";
        }

        if (!password.equals(confirmPassword)) {
            return "Mật khẩu xác nhận không trùng khớp";
        }

        return null;
    }

    private String normalize(String value) {
        return value == null ? null : value.trim();
    }

    private void writeJson(HttpServletResponse resp, JsonObject jsonResponse, String status, String message) throws IOException {
        jsonResponse.addProperty("status", status);
        jsonResponse.addProperty("message", message);
        PrintWriter out = resp.getWriter();
        out.print(jsonResponse.toString());
    }
}

package nlu.fit.web.souvenirecommerce.auth.servlet;

import com.google.gson.JsonObject;
import jakarta.servlet.ServletException;
import jakarta.servlet.annotation.WebServlet;
import jakarta.servlet.http.HttpServlet;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import jakarta.servlet.http.HttpSession;
import nlu.fit.web.souvenirecommerce.dao.IUserDAO;
import nlu.fit.web.souvenirecommerce.auth.dao.AuthDAO;
import nlu.fit.web.souvenirecommerce.enums.Gender;
import nlu.fit.web.souvenirecommerce.util.EmailUtil;

import java.io.IOException;
import java.io.PrintWriter;

@WebServlet(urlPatterns = {"/api/signup", "/signup"})
public class SignupServlet extends HttpServlet {
    private IUserDAO userDAO;

    @Override
    public void init() throws ServletException {
        userDAO = new AuthDAO();
    }

    @Override
    protected void doGet(HttpServletRequest req, HttpServletResponse resp) throws ServletException, IOException {
        req.getRequestDispatcher("/WEB-INF/views/auth/signup.jsp").forward(req, resp);
    }

    protected void doPost(HttpServletRequest req, HttpServletResponse resp) throws ServletException, IOException {
        resp.setContentType("application/json;charset=UTF-8");
        req.setCharacterEncoding("UTF-8");

        JsonObject jsonResponse = new JsonObject();
        Try {
            String email = EmailUtil.normalizeEmail(req.getParameter("email"));
            String firstName = normalize(req.getParameter("firstName"));
            String lastName = normalize(req.getParameter("lastName"));
            String phone = normalize(req.getParameter("phone"));
            String gender = normalize(req.getParameter("gender"));
            String password = req.getParameter("password");
            String confirmPassword = req.getParameter("confirmPassword");

            String validationError = validate(email, firstName, lastName, phone, gender, password, confirmPassword);
            if (validationError != null) {
                writeJson(resp, jsonResponse, "error", validationError);
                return;
            }

            HttpSession session = req.getSession(false);
            String verifiedEmail = session == null ? null : (String) session.getAttribute("signupVerifiedEmail");
            if (!email.equals(verifiedEmail)) {
                writeJson(resp, jsonResponse, "error", "Vui lòng xác thực email trước khi đăng ký");
                return;
            }

            if (userDAO.hasEmailExist(email)) {
                writeJson(resp, jsonResponse, "error", "Email này đã được đăng ký");
                return;
            }

            boolean registered = userDAO.createUser(email, password, firstName, lastName, phone, gender).isPresent();
            if (!registered) {
                writeJson(resp, jsonResponse, "error", "Không thể tạo tài khoản. Vui lòng thử lại");
                return;
            }

            if (session != null) {
                session.removeAttribute("signupEmail");
                session.removeAttribute("signupVerifiedEmail");
            }

            writeJson(resp, jsonResponse, "success", "Tạo tài khoản thành công");
        } catch (Exception e) {
            System.err.println("Error during signup: " + e.getMessage());
            e.printStackTrace();
            writeJson(resp, jsonResponse, "error", "Có lỗi xảy ra. Vui lòng thử lại");
        }

        // Create UserSession and setAttributes
    }

    private String validate(String email, String firstName, String lastName, String phone, String gender,
                            String password, String confirmPassword) {
        if (email == null || email.isEmpty()) {
            return "Email không được để trống";
        }

        if (!email.matches("^[A-Za-z0-9+_.-]+@(.+)$")) {
            return "Email không hợp lệ";
        }

        if (lastName == null || lastName.isBlank()) {
            return "Họ không được để trống";
        }

        if (firstName == null || firstName.isBlank()) {
            return "Tên không được để trống";
        }

        if (phone == null || !phone.matches("^[0-9]{10,20}$")) {
            return "Số điện thoại phải từ 10-20 chữ số";
        }

        if (gender == null || gender.isBlank()) {
            return "Vui lòng chọn giới tính";
        }

        try {
            Gender.valueOf(gender.toUpperCase());
        } catch (IllegalArgumentException e) {
            return "Giới tính không hợp lệ";
        }

        if (password == null || password.length() < 8) {
            return "Mật khẩu phải ít nhất 8 ký tự";
        }

        if (!password.equals(confirmPassword)) {
            return "Mật khẩu xác nhận không trùng khớp";
        }

        return null;
    }

    private String normalize(String value) {
        return value == null ? null : value.trim();
    }

    private void writeJson(HttpServletResponse resp, JsonObject jsonResponse, String status, String message) throws IOException {
        jsonResponse.addProperty("status", status);
        jsonResponse.addProperty("message", message);
        PrintWriter out = resp.getWriter();
        out.print(jsonResponse.toString());
    }
}

package nlu.fit.web.souvenirecommerce.controller;

import jakarta.servlet.ServletException;
import jakarta.servlet.annotation.WebServlet;
import jakarta.servlet.http.HttpServlet;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import jakarta.servlet.http.HttpSession;
import nlu.fit.web.souvenirecommerce.dao.OrderDAO;
import nlu.fit.web.souvenirecommerce.model.Order;
import nlu.fit.web.souvenirecommerce.model.OrderItem;
import nlu.fit.web.souvenirecommerce.model.entity.User;

import java.io.IOException;
import java.util.List;

@WebServlet("/user/orders")
public class UserOrderController extends HttpServlet {

    private final OrderDAO orderDAO = new OrderDAO();

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {

        HttpSession session = request.getSession(false);

        if (session == null) {
            response.sendRedirect(request.getContextPath() + "/login");
            return;
        }

        User user = (User) session.getAttribute("userInSession");
        if (user == null) {
            response.sendRedirect(request.getContextPath() + "/login");
            return;
        }

        String action = request.getParameter("action");
        action = (action != null) ? action.trim() : "";

        if ("detail".equals(action)) {
            viewOrderDetail(request, response, user);
        } else {
            viewOrderList(request, response, user);
        }
    }

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {

        response.sendRedirect(request.getContextPath() + "/user/orders");
    }

    private void viewOrderList(HttpServletRequest request,
                               HttpServletResponse response,
                               User user)
             throws ServletException, IOException {

         List<Order> orderList = orderDAO.getOrdersByUserId(user.getId().intValue());

         request.setAttribute("orderList", orderList);
         request.setAttribute("pageTitle", "Đơn hàng");
         request.setAttribute("pageCss", "account/account-layout.css");
         request.setAttribute("contentCss", "account/orders.css");
         request.setAttribute("pageJs", "account/profile.js");
         request.setAttribute("pageContent", "orders.jsp");
         request.setAttribute("contentPage", "/WEB-INF/views/account/account_layout.jsp");

         request.getRequestDispatcher("/WEB-INF/layout/base.jsp").forward(request, response);
     }

     private void viewOrderDetail(HttpServletRequest request,
                                  HttpServletResponse response,
                                  User user)
             throws ServletException, IOException {

         int orderId;
         try {
             orderId = Integer.parseInt(request.getParameter("id"));
         } catch (NumberFormatException e) {
             response.sendRedirect(request.getContextPath() + "/user/orders");
             return;
         }

         Order order = orderDAO.getOrderById(orderId);

         if (order == null || user.getId() == null || order.getUserId() != user.getId().intValue()) {
             response.sendRedirect(request.getContextPath() + "/user/orders");
             return;
         }

         List<OrderItem> orderItems = orderDAO.getOrderItems(orderId);

         request.setAttribute("order", order);
         request.setAttribute("orderItems", orderItems);
         request.setAttribute("pageTitle", "Chi tiết đơn hàng");
         request.setAttribute("pageCss", "account/account-layout.css");
         request.setAttribute("contentCss", "account/profile.css");
         request.setAttribute("pageJs", "account/profile.js");
         request.setAttribute("pageContent", "orders.jsp");
         request.setAttribute("contentPage", "/WEB-INF/views/account/account_layout.jsp");

         request.getRequestDispatcher("/WEB-INF/layout/base.jsp").forward(request, response);
     }
}

