.profile-panel {
    background: var(--surface-default);
    border: 1px solid var(--border-subtle);
    border-radius: var(--radius-md);
    box-shadow: var(--shadow-sm);
}

.secondary-button,
.text-button,
.primary-button {
    min-height: 38px;
    border-radius: var(--radius-sm);
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: 8px;
    font-weight: 700;
    line-height: 1;
    transition: background-color 0.2s ease, border-color 0.2s ease, color 0.2s ease, box-shadow 0.2s ease;
}

.account-heading {
    display: flex;
    justify-content: space-between;
    gap: 16px;
    align-items: end;
}

.account-heading h1 {
    font-size: 28px;
    line-height: 1.25;
}

.account-heading p,
.panel-header p {
    margin-top: 6px;
    color: var(--text-soft);
}

.profile-alert {
    border-radius: var(--radius-md);
    border: 1px solid var(--success-border);
    background: var(--success-bg);
    color: var(--success);
    padding: 12px 14px;
    font-weight: 650;
}

.profile-alert--error {
    border-color: var(--danger-border);
    background: var(--danger-bg);
    color: var(--danger);
}

.profile-panel {
    padding: 22px;
}

.panel-header {
    margin-bottom: 22px;
}

.panel-header h2 {
    font-size: 20px;
}

.panel-header--split {
    display: flex;
    justify-content: space-between;
    gap: 18px;
    align-items: center;
}

.profile-form {
    display: grid;
    gap: 18px;
}

.profile-form *,
.profile-form *::before,
.profile-form *::after {
    box-sizing: border-box;
}

.address-form .form-grid {
    display: grid;
    grid-template-columns: repeat(2, minmax(0, 1fr));
    gap: 16px;
}

.profile-panel .form-table {
    width: 100%;
    border-collapse: separate;
    border-spacing: 0;
    table-layout: fixed;
    margin: 0 0 18px;
    overflow: hidden;
    border: 1px solid var(--border-subtle);
    border-radius: var(--radius-md);
    background: var(--surface-default);
}

.profile-panel .form-table tr {
    border-bottom: 1px solid var(--border-subtle);
}

.profile-panel .form-table tr:last-child {
    border-bottom: none;
}

.profile-panel .form-table th,
.profile-panel .form-table td {
    padding: 14px 16px;
    vertical-align: middle;
    text-align: left;
}

.profile-panel .form-table tbody tr td {
    border-bottom: 1px solid var(--border-subtle);
}

.profile-panel .form-table tbody tr:last-child td {
    border-bottom: none;
}

.profile-panel .form-table th {
    width: 190px;
    background: var(--surface-subtle);
    border-bottom: 1px solid var(--border-subtle);
}

.profile-panel .form-table th label,
.profile-panel .form-table th span {
    color: var(--text-strong);
    font-size: 14px;
    font-weight: 700;
}

.profile-panel .form-table td {
    min-width: 0;
    background: var(--surface-default);
}

.profile-panel .form-table tr:last-child th,
.profile-panel .form-table tr:last-child td {
    border-bottom: none;
}

.profile-form .form-table td input[type="text"],
